// dist/deployer/index.js
import { execFile } from "node:child_process";
import { promisify } from "node:util";
var exec = promisify(execFile);
var git = (args, cwd) => exec("git", args, { cwd });
var deploy = async (options) => {
  const { repoUrl, directory, message = "deploy" } = options;
  await git(["init"], directory);
  await git(["checkout", "--orphan", "gh-pages"], directory);
  await git(["add", "."], directory);
  await git(["config", "user.name", "github-weekly-reporter"], directory);
  await git(["config", "user.email", "github-weekly-reporter@users.noreply.github.com"], directory);
  await git(["commit", "-m", message], directory);
  await git(["push", repoUrl, "gh-pages", "--force"], directory);
};

// dist/cli/commands/deploy.js
var run2 = async (options) => {
  const weekId = getWeekId();
  console.log(`Deploying ${options.directory} to gh-pages...`);
  await deploy({
    repoUrl: options.repo,
    directory: options.directory,
    message: `report: ${weekId.path}`
  });
  console.log("Deployed successfully!");
};
var registerDeploy = (program3) => {
  program3.command("deploy").description("Deploy generated report to GitHub Pages (gh-pages branch)").requiredOption("-d, --directory <dir>", "Directory containing generated report files", "./report").requiredOption("-r, --repo <url>", "Repository URL to push to (e.g. https://github.com/user/repo.git)").action(async (opts) => {
    try {
      await run2({
        directory: opts.directory,
        repo: opts.repo
      });
    } catch (error) {
      console.error("Error:", error instanceof Error ? error.message : error);
      process.exit(1);
    }
  });
};

// dist/cli/index.js
var program2 = new Command().name("github-weekly-reporter").description("Generate beautiful weekly GitHub activity reports").version("0.1.0");
registerGenerate(program2);
registerDeploy(program2);
program2.parse();
